<script setup lang="ts">
import{computed,onMounted,ref}from'vue';import{useI18n}from'vue-i18n';import{getTaskConfig,saveTaskConfig}from'@/api/prompts';import{useUnsavedChanges}from'@/composables/useUnsavedChanges';import type{TaskIsolationConfig}from'@/types/prompts'
const{t}=useI18n();const config=ref<TaskIsolationConfig|null>(null),baseline=ref(''),busy=ref(false),error=ref(''),success=ref('');const dirty=computed(()=>!!config.value&&JSON.stringify(config.value)!==baseline.value);useUnsavedChanges(dirty,()=>t('taskIsolation.unsavedConfirm'));async function load(){try{config.value=await getTaskConfig();baseline.value=JSON.stringify(config.value)}catch(e){error.value=e instanceof Error?e.message:''}}async function save(){if(!config.value||busy.value)return;busy.value=true;error.value='';try{config.value=await saveTaskConfig(config.value);baseline.value=JSON.stringify(config.value);success.value=t('taskIsolation.saved')}catch(e){error.value=e instanceof Error?e.message:''}finally{busy.value=false}}onMounted(load)
</script>
<template><section class="page"><header class="page-heading"><div><p class="eyebrow">{{t('taskIsolation.eyebrow')}}</p><h1>{{t('taskIsolation.title')}}</h1></div><button class="primary-button" :disabled="busy||!dirty" @click="save">{{t('taskIsolation.save')}}</button></header><p v-if="error" class="error-text">{{error}}</p><p v-if="success" class="success-text">{{success}}</p><template v-if="config"><section class="form-section"><h2>{{t('taskIsolation.mode')}}</h2><div class="form-grid"><label class="check"><input v-model="config.promptEnabled" type="checkbox">{{t('taskIsolation.promptEnabled')}}</label><label>{{t('taskIsolation.injectionMode')}}<select v-model="config.injectionMode"><option value="normal">{{t('taskIsolation.normal')}}</option><option value="bannerlord">{{t('taskIsolation.bannerlord')}}</option></select></label><label class="check"><input v-model="config.playerFriendly" type="checkbox">{{t('taskIsolation.master')}}</label><label class="check"><input v-model="config.playerDialogue" type="checkbox">{{t('taskIsolation.playerDialogue')}}</label><label class="check"><input v-model="config.actionDialogue" type="checkbox">{{t('taskIsolation.actionDialogue')}}</label><label class="check"><input v-model="config.npcDialogue" type="checkbox">{{t('taskIsolation.npcDialogue')}}</label></div></section><section class="form-section"><h2>{{t('taskIsolation.rules')}}</h2><div class="rule-grid"><article><h3>{{t('taskIsolation.allowed')}}</h3><code>player_npc_dialogue</code><code>player_npc_action_dialogue</code><code>npc_initiated_player_dialogue</code></article><article><h3>{{t('taskIsolation.passthrough')}}</h3><p>{{t('taskIsolation.passthroughDetail')}}</p></article></div><p>{{t('taskIsolation.fallback')}}</p></section></template></section></template>
